1	import { describe, it, expect } from "vitest";
2	import { quote, claim, createPolicy } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote - basic functionality", () => {
6	    it("should return 0 premium for empty item list", () => {
7	      expect(quote([])).toBe(0);
8	    });
9	    it("should return 100G base premium for single sword", () => {
10	      expect(quote([{ type: "sword" }])).toBe(100);
11	    });
12	    it("should return 60G base premium for single amulet", () => {
13	      expect(quote([{ type: "amulet" }])).toBe(60);
14	    });
15	    it("should return 80G base premium for single staff", () => {
16	      expect(quote([{ type: "staff" }])).toBe(80);
17	    });
18	    it("should return 40G base premium for single potion", () => {
19	      expect(quote([{ type: "potion" }])).toBe(40);
20	    });
21	    it("should sum premiums for two different items", () => {
22	      expect(quote([{ type: "sword" }, { type: "amulet" }])).toBe(160);
23	    });
24	    it("should sum premiums for multiple items", () => {
25	      expect(quote([{ type: "sword" }, { type: "amulet" }, { type: "staff" }])).toBe(240);
26	    });
27	    it("should calculate base premium for single component", () => {
28	      expect(quote([{ type: "component" }])).toBe(25);
29	    });
30	    it("should apply 60G discount for three identical components", () => {
31	      expect(quote([{ type: "component", count: 3 }])).toBe(35);
32	    });
33	    it("should sum premiums correctly with mixed items and components", () => {
34	      expect(quote([{ type: "sword" }, { type: "component", count: 3 }])).toBe(135);
35	    });
36	  });
37	
38	  describe("claim - basic functionality", () => {
39	    it("should reject claim on non-existent policy", () => {
40	      const result = claim("non-existent", 500);
41	      expect(result).toEqual({ policyId: "non-existent", payout: 0, error: "Policy not found" });
42	    });
43	    it("should apply 100G deductible to damage claim", () => {
44	      const policy = createPolicy([{ type: "sword" }]);
45	      const result = claim(policy.id, 150);
46	      expect(result.payout).toBe(50);
47	    });
48	    it("should return 0 payout when damage equals deductible", () => {
49	      const policy = createPolicy([{ type: "sword" }]); // 100G premium = 100G deductible
50	      const result = claim(policy.id, 100); // damage = 100, after deductible = 0
51	      expect(result.payout).toBe(0);
52	    });
53	    it("should cap payout at 2x insurance sum", () => {
54	      const policy = createPolicy([{ type: "sword" }]); // 100G premium
55	      const result = claim(policy.id, 400); // damage = 400, after deductible = 300, cap at 2x premium = 200
56	      expect(result.payout).toBe(200); // Should be capped at 2x (200G max)
57	    });
